import re,sys
src=open(sys.argv[1],encoding='utf-8').read()
lines=open(sys.argv[2],encoding='utf-8').read().splitlines()
missing=[]
for ln in lines:
    # prose quotes
    if '— quote:' in ln:
        m=re.search(r'— quote:\s*"(.+?)"\s*$',ln)
        if m:
            q=m.group(1)
            if q not in src: missing.append(('PROSE',q))
    # table evidence quotes: last cell wrapped in "..."
    elif ln.startswith('|') and '"' in ln:
        cells=[c.strip() for c in ln.strip().strip('|').split('|')]
        for c in cells:
            if c.startswith('"') and c.endswith('"'):
                q=c[1:-1]
                if q not in src: missing.append(('TABLE',q))
print("MISSING COUNT:",len(missing))
for k,q in missing: print(k,"::",q)
PY
